reference_solution:
val items = [
  { id: 4, matched: true },
  { id: 5, matched: false },
  { id: 7, matched: true }
];

var lastMatch = "none";
for (item in items) {
  if (item.matched) {
    print(item.id);
    lastMatch = item.id;
  }
}

print(lastMatch);
